import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Safety/cloudflare-api-token.md","filePath":"ps/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"ps/Safety/cloudflare-api-token.md"};function n(c,e,s,p,u,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>د Cloudflare API credentials ImgBed ته اجازه ورکوي چې د فایلونو له بدلون وروسته د Cloudflare CDN cache پاک کړي.</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="چېرته-یې-تنظیم-کړئ" tabindex="-1">چېرته یې تنظیم کړئ <a class="header-anchor" href="#چېرته-یې-تنظیم-کړئ" aria-label="Permalink to &quot;چېرته یې تنظیم کړئ&quot;">​</a></h2><p>admin panel پرانیزئ، بیا دې ځای ته لاړ شئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>دا fields باید ډک کړئ:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="دا-setting-څه-کوي" tabindex="-1">دا setting څه کوي <a class="header-anchor" href="#دا-setting-څه-کوي" aria-label="Permalink to &quot;دا setting څه کوي&quot;">​</a></h2><p>Cloudflare ښايي public image URLs cache کړي.</p><p>Cache د image delivery چټکوي، خو کله چې فایل delete، block، replace یا move کړئ، زاړه content د یو څه وخت لپاره لا هم ښکاره پاتې کېدای شي.</p><p>کله چې Cloudflare API credentials تنظیم شي، ImgBed د دغو operations تر بشپړېدو وروسته د اړوند Cloudflare cache د purge هڅه کوي.</p><p>دا په دې حالتونو کې ګټور دی:</p><ul><li>image delete کوئ او غواړئ public link ژر تر ژره کار پرېږدي.</li><li>image block کوئ او غواړئ visitors اصلي فایل نور ونه ویني.</li><li>په هماغه نوم فایل replace کوئ او غواړئ visitors نوی version ژر وویني.</li><li>فایلونه move یا rename کوئ او غواړئ د زاړه path cache ژر refresh شي.</li><li>public access rules بدلوئ او غواړئ public gallery یا random image cache ژر update شي.</li></ul><h2 id="که-تش-یې-پرېږدئ-څه-کېږي" tabindex="-1">که تش یې پرېږدئ څه کېږي <a class="header-anchor" href="#که-تش-یې-پرېږدئ-څه-کېږي" aria-label="Permalink to &quot;که تش یې پرېږدئ څه کېږي&quot;">​</a></h2><p>ImgBed له دې setting پرته هم عادي کار کوي.</p><p>یوازینی توپیر دا دی چې ImgBed به د Cloudflare CDN cache فعال purge نه کوي. visitors ښايي زاړه content تر هغه وویني چې Cloudflare cache په طبیعي ډول expire شي.</p><h2 id="zone-id-څنګه-پیدا-کړئ" tabindex="-1">Zone ID څنګه پیدا کړئ <a class="header-anchor" href="#zone-id-څنګه-پیدا-کړئ" aria-label="Permalink to &quot;Zone ID څنګه پیدا کړئ&quot;">​</a></h2><p>Zone ID د هغه site Cloudflare Zone ID دی چې ستاسو ImgBed domain پکې کارېږي.</p><ol><li>Cloudflare dashboard ته sign in وکړئ.</li><li>هغه site پرانیزئ چې ستاسو ImgBed domain پکې دی.</li><li>د site overview page کې <code>Zone ID</code> ومومئ.</li><li>هغه copy کړئ او په ImgBed کې د <code>Zone ID</code> field ته یې واچوئ.</li></ol><p>دا د site Zone ID دی، account ID نه دی.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>هغه email address ولیکئ چې Cloudflare ته پرې sign in کوئ.</p><p>دا باید له لاندې API Key سره برابر وي.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>خپل Cloudflare Global API Key ولیکئ.</p><ol><li>Cloudflare dashboard ته sign in وکړئ.</li><li>خپل profile پرانیزئ.</li><li>API Tokens page ته لاړ شئ.</li><li><code>Global API Key</code> ومومئ.</li><li>view یې کړئ او copy یې کړئ.</li><li>په ImgBed کې یې د <code>API Key</code> field ته paste کړئ.</li></ol><p><img src="'+l+'" alt="View global API key" loading="lazy"></p><h2 id="کله-اغېز-کوي" tabindex="-1">کله اغېز کوي <a class="header-anchor" href="#کله-اغېز-کوي" aria-label="Permalink to &quot;کله اغېز کوي&quot;">​</a></h2><p>د fields له ډکولو وروسته settings save کړئ.</p><p>راتلونکي file changes به په اتومات ډول د Cloudflare cache purge کولو هڅه وکړي. تېر operations retroactively نه purge کېږي. که له دې setting مخکې مو فایل delete یا replace کړی وي، د Cloudflare cache expire کېدو ته انتظار وکړئ یا یې په Cloudflare کې manually purge کړئ.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ایا-دا-اړین-دی؟" tabindex="-1">ایا دا اړین دی؟ <a class="header-anchor" href="#ایا-دا-اړین-دی؟" aria-label="Permalink to &quot;ایا دا اړین دی؟&quot;">​</a></h3><p>نه.</p><p>که ستاسو domain Cloudflare نه کاروي، یا د CDN cache delay درته ستونزه نه وي، تش یې پرېښودلای شئ.</p><h3 id="غلط-credentials-uploads-خرابوي؟" tabindex="-1">غلط Credentials uploads خرابوي؟ <a class="header-anchor" href="#غلط-credentials-uploads-خرابوي؟" aria-label="Permalink to &quot;غلط Credentials uploads خرابوي؟&quot;">​</a></h3><p>عموما نه.</p><p>غلط credentials یوازې ImgBed د Cloudflare cache له purge کولو منع کوي. upload او عادي file access باید دوام وکړي.</p><h3 id="ولې-deleted-image-لا-هم-پرانیستل-کېږي؟" tabindex="-1">ولې Deleted Image لا هم پرانیستل کېږي؟ <a class="header-anchor" href="#ولې-deleted-image-لا-هم-پرانیستل-کېږي؟" aria-label="Permalink to &quot;ولې Deleted Image لا هم پرانیستل کېږي؟&quot;">​</a></h3><p>تر ټولو عام علت دا دی چې Cloudflare لا هم زوړ فایل cache کړی وي.</p><p>د سم Cloudflare API credentials په شتون کې، ImgBed د فایل د delete کېدو پر وخت اړوند URL cache purge کوي.</p><h3 id="ولې-د-فایل-له-replace-وروسته-لا-هم-زوړ-image-وینم؟" tabindex="-1">ولې د فایل له Replace وروسته لا هم زوړ Image وینم؟ <a class="header-anchor" href="#ولې-د-فایل-له-replace-وروسته-لا-هم-زوړ-image-وینم؟" aria-label="Permalink to &quot;ولې د فایل له Replace وروسته لا هم زوړ Image وینم؟&quot;">​</a></h3><p>دا هم عموما د CDN cache له امله وي.</p><p>کله چې دا setting تنظیم وي، ImgBed د هماغه نوم فایل overwrite کېدو پر وخت د زاړه URL cache purge کولو هڅه کوي.</p>',44)])])}const b=i(d,[["render",n]]);export{I as __pageData,b as default};
